/*
Data contract class for the document attachment business event on purchase agreements.
*/
[DataContract]
class ETGDMSIntDocumentAttachmentContract extends BusinessEventsContract
{
    str   dealNumber;
    str   DMSDealNumber;
    str   documentUrl;
    str   dealType;
    str   documentType;
    RecId recId;
    str  documentDate;
    FileId   fileId;

}

Method.Source:
[DataMemberAttribute('DealNumber')]
public str parmDealNumber(str _dealNumber = dealNumber)
{
    dealNumber = _dealNumber;
    return dealNumber;
}

[DataMemberAttribute('DocumentUrl')]
public str parmDocumentUrl(str _documentUrl = documentUrl)
{
    documentUrl = _documentUrl;
    return documentUrl;
}

[DataMemberAttribute('DealType')]
public str parmDealType(str _dealType = dealType)
{
    dealType = _dealType;
    return dealType;
}

[DataMemberAttribute('DMSDealNumber')]
public str parmDMSDealNumber(str _DMSDealNumber = DMSDealNumber)
{
    DMSDealNumber = _DMSDealNumber;
    return DMSDealNumber;
}

[DataMemberAttribute('DocumentType')]
public str parmDocumentType(str _documentType = documentType)
{
    documentType = _documentType;
    return documentType;
}

[DataMemberAttribute('DocumentDate')]
public str parmDocumentDate(str _documentDate = documentDate)
{
    documentDate = _documentDate;
    return documentDate;
}

[DataMemberAttribute('FileId')]
public FileId parmFileId(FileId _fileId = fileId)
{
    fileId = _fileId;
    return fileId;
}

/// <summary>
/// Initializes the contract from PurchAgreementHeader and DocuRef
/// </summary>
private void initializePurch(PurchAgreementHeader _purchAgreementHeader, DocuRef _docuRef)
{
    DocuValue docuValue;
    DocuType  docuType;
    DocuRef docuRef;
    str formattedDateTime;

    select firstOnly docuValue
        where docuValue.RecId == _docuRef.ValueRecId;

    select firstOnly docuRef
        where docuRef.RecId == _docuRef.RecId
    join docuType
        where docuType.TypeId == docuRef.TypeId;

    this.dealNumber      = _purchAgreementHeader.PurchNumberSequence;
    this.dealType        = "Purchase";
    this.DMSDealNumber   = _purchAgreementHeader.ETGDMSDealNumbers;
    this.documentUrl     =  docuValue ? docuValue.AccessInformation : '';
    this.documentType    =  docuType ? docuType.Name : '';
    formattedDateTime    = DateTimeUtil::toStr(_docuRef.CreatedDateTime);
    this.documentDate    = formattedDateTime;
    this.fileId          =  docuValue.FileId;
}

/// <summary>
/// Initializes the contract from SalesAgreementHeader and DocuRef
/// </summary>
private void initializeSales(SalesAgreementHeader _salesAgreementHeader, DocuRef _docuRef)
{
    DocuValue docuValue;
    DocuType  docuType;
    DocuRef docuRef;
    str formattedDateTime;

    select firstOnly docuValue
        where docuValue.RecId == _docuRef.ValueRecId;

    select firstOnly docuRef
        where docuRef.RecId == _docuRef.RecId
    join docuType
        where docuType.TypeId == docuRef.TypeId;

    this.dealNumber      = _salesAgreementHeader.SalesNumberSequence;
    this.dealType        = "Sales";
    this.DMSDealNumber   = _salesAgreementHeader.ETGDMSDealNumber;
    this.documentUrl     =  docuValue ? docuValue.AccessInformation : '';
    this.documentType    =  docuType ? docuType.Name : '';
    formattedDateTime    = DateTimeUtil::toStr(_docuRef.CreatedDateTime);
    this.documentDate    = formattedDateTime;
    this.fileId          =  docuValue.FileId;
}

/// <summary> private ctor to force using factory </summary>
private void new()
{
    super();
}

public static ETGDMSIntDocumentAttachmentContract newFromPurchAgreement(PurchAgreementHeader _purchAgreementHeader, DocuRef _docuRef)
{
    ETGDMSIntDocumentAttachmentContract contract = new ETGDMSIntDocumentAttachmentContract();
    contract.initializePurch(_purchAgreementHeader, _docuRef);
    return contract;
}

public static ETGDMSIntDocumentAttachmentContract newFromSalesAgreement(SalesAgreementHeader _salesAgreementHeader, DocuRef _docuRef)
{
    ETGDMSIntDocumentAttachmentContract contract = new ETGDMSIntDocumentAttachmentContract();
    contract.initializeSales(_salesAgreementHeader, _docuRef);
    return contract;
}
